const input = $input.first().json;

// ── Pull directly from Google Sheets column names ─────────
const raw = input['Timestamp'];
const name = input['Name'];
const email = input['Email'];
const phone = input['Phone number'];

// ── Validate required fields ──────────────────────────────
if (!raw) throw new Error('Timestamp is missing from Google Sheets data');
if (!name) throw new Error('Name is missing from Google Sheets data');
if (!email) throw new Error('Email is missing from Google Sheets data');

// ── Parse timestamp: "3/6/2026 13:37:06" → ISO 8601 ──────
let isoString;

if (raw.includes('T')) {
  isoString = raw; // already ISO, skip parsing
} else {
  const [datePart, timePart] = raw.trim().split(' ');
  const [month, day, year]   = datePart.split('/');
  const [hours, minutes, seconds] = timePart.split(':');

  isoString = `${year}-${month.padStart(2,'0')}-${day.padStart(2,'0')}T${hours.padStart(2,'0')}:${minutes.padStart(2,'0')}:${(seconds || '00').padStart(2,'0')}`;
}

const parsed = new Date(isoString);

if (isNaN(parsed.getTime())) {
  throw new Error(`Could not parse timestamp: "${raw}"`);
}

// ── Return clean normalized data ──────────────────────────
return [{
  json: {
    name:          name,
    email:         email,
    phone:         phone,
    registered_at: parsed.toISOString()
  }
}];

const input = $input.first().json;

// ── Set your webinar date and time here ───────────────────
// Format: YYYY-MM-DDTHH:MM:SS  (24hr, your local time)
const WEBINAR_DATETIME = '2026-03-18T18:00:00';

// ── Your timezone offset from UTC ─────────────────────────
// Lagos/Nigeria = +01:00
const TIMEZONE_OFFSET = '+01:00';

return [{
  json: {
    ...input,
    webinar_datetime: `${WEBINAR_DATETIME}${TIMEZONE_OFFSET}`
  }
}];

const input        = $input.first().json;
const now          = new Date();
const webinarTime  = new Date(input.webinar_datetime);
const registeredAt = new Date(input.registered_at);

// ── Safety check: webinar must be in the future ───────────
if (isNaN(webinarTime.getTime())) {
  throw new Error(`Invalid webinar_datetime: "${input.webinar_datetime}"`);
}

if (webinarTime <= now) {
  // Webinar already passed — send nothing
  return [];
}

// ── Build the 6AM same-day reminder time ─────────────────
const sameDaySixAM = new Date(webinarTime);
sameDaySixAM.setHours(6, 0, 0, 0);

// ── All possible reminders ────────────────────────────────
const allReminders = [
  {
    id:    '7day',
    label: '7 Days Before',
    time:  new Date(webinarTime.getTime() - 7 * 24 * 60 * 60 * 1000)
  },
  {
    id:    '3day',
    label: '3 Days Before',
    time:  new Date(webinarTime.getTime() - 3 * 24 * 60 * 60 * 1000)
  },
  {
    id:    'sameday_6am',
    label: 'Day-Of 6AM',
    time:  sameDaySixAM
  },
  {
    id:    '1hour',
    label: '1 Hour Before',
    time:  new Date(webinarTime.getTime() - 1 * 60 * 60 * 1000)
  }
];

// ── Filter: only keep reminders still in the future ───────
const validReminders = allReminders.filter(r => r.time > now);

if (validReminders.length === 0) {
  // Registered too late — no reminders apply
  return [];
}

// ── Output one item per valid reminder ────────────────────
return validReminders.map(r => ({
  json: {
    name:             input.name,
    email:            input.email,
    phone:            input.phone,
    registered_at:    input.registered_at,
    webinar_datetime: input.webinar_datetime,
    reminder_id:      r.id,
    reminder_label:   r.label,
    send_at:          r.time.toISOString(),
    hours_until_send: Math.round(((r.time - now) / (1000 * 60 * 60)) * 10) / 10
  }
}));

const input       = $input.first().json;
const webinarTime = new Date(input.webinar_datetime);

// ── Format readable date and time ────────────────────────
const formattedDate = webinarTime.toLocaleDateString('en-NG', {
  weekday: 'long',
  year:    'numeric',
  month:   'long',
  day:     'numeric',
  timeZone: 'Africa/Lagos'
});

const formattedTime = webinarTime.toLocaleTimeString('en-NG', {
  hour:     '2-digit',
  minute:   '2-digit',
  timeZone: 'Africa/Lagos',
  timeZoneName: 'short'
});

// ── Webinar join link ─────────────────────────────────────
const JOIN_LINK = 'https://your-webinar-link.com'; // ← update this

// ── Message templates per reminder type ──────────────────
const templates = {

  '7day': {
    subject: `📅 Your Webinar is in 7 Days, ${input.name}!`,
    body: `Hi ${input.name},

You're registered for our upcoming webinar — and it's just 7 days away!

📅 Date: ${formattedDate}
🕐 Time: ${formattedTime}

Add it to your calendar now so you don't miss a thing. We'll be covering everything you need to know, live and in real time.

👉 Join the Webinar: ${JOIN_LINK}

See you there!`
  },

  '3day': {
    subject: `⏳ Only 3 Days Left — Get Ready, ${input.name}!`,
    body: `Hi ${input.name},

Your webinar is just 3 days away — it's almost time!

📅 Date: ${formattedDate}
🕐 Time: ${formattedTime}

Make sure you've saved the link below and cleared your schedule. You won't want to miss this.

👉 Join the Webinar: ${JOIN_LINK}

We'll see you there!`
  },

  'sameday_6am': {
    subject: `🌅 Today's the Day, ${input.name}! Webinar Tonight`,
    body: `Good morning ${input.name}!

Your webinar is happening TODAY at ${formattedTime}.

Clear your schedule, grab a notebook, and come ready to engage. Rooms open 10 minutes before the session starts.

👉 Join the Webinar: ${JOIN_LINK}

We're looking forward to seeing you today! 🚀`
  },

  '1hour': {
    subject: `🔔 Starting in 1 Hour — Don't Miss It, ${input.name}!`,
    body: `Hi ${input.name},

This is your final reminder — your webinar kicks off in just ONE HOUR!

🕐 Start Time: ${formattedTime}

Click the link below to join. The room is already open so you can jump in early and get settled.

👉 Join Now: ${JOIN_LINK}

We'll see you in there! 🎉`
  }

};

// ── Select correct template ───────────────────────────────
const message = templates[input.reminder_id];

if (!message) {
  throw new Error(`No template found for reminder_id: "${input.reminder_id}"`);
}

return [{
  json: {
    ...input,
    subject: message.subject,
    body:    message.body
  }
}];
